# solution.py
"""Office_Task_Collaboration_Manager.

A thread-safe, in-memory collaborative task management system.  The public
surface is the :class:`TeamCollaborationManager`, which orchestrates users,
projects, tasks, messaging, a performance dashboard, reporting (CSV/PDF
export) and lightweight notifications.

Design notes
------------
* A single re-entrant lock guards every mutation.  All sub-stores share the
  very same lock object so cross-store operations stay consistent and the
  whole system can be driven safely from many threads at once.
* Every value returned to a caller is a deep copy.  Callers may freely mutate
  what they receive without ever corrupting internal state.
* Identifiers are globally unique and monotonically increasing, starting at 1.
"""

import copy
import csv
import enum
import io
import itertools
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(enum.Enum):
    """Lifecycle state of a task."""

    NOT_STARTED = "Not Started"
    IN_PROGRESS = "In Progress"
    COMPLETED = "Completed"


class UserRole(enum.Enum):
    """Role used for role-based access control."""

    ADMIN = "admin"
    MANAGER = "manager"
    MEMBER = "member"
    VIEWER = "viewer"


class Priority(enum.Enum):
    """Relative urgency of a task."""

    LOW = "low"
    MEDIUM = "medium"
    HIGH = "high"
    URGENT = "urgent"


class ReportFormat(enum.Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Kinds of report the manager can generate."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when inputs fail validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime
    id: Optional[int] = None


@dataclass
class User:
    """A registered member of the workspace."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A container that groups tasks and conversations."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    """A unit of work that can be assigned, tracked and discussed."""

    id: int
    project_id: int
    title: str
    description: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    priority: Priority
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Message:
    """A comment, optionally with attachments, on a project or task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """Peer feedback assigned to a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


@dataclass
class Notification:
    """An in-memory notification delivered to a user."""

    id: int
    user_id: int
    event: str
    detail: str
    created_at: datetime
    read: bool = False


# ---------------------------------------------------------------------------
# Internal store
# ---------------------------------------------------------------------------
class _Store:
    """A thin keyed container that shares the manager's lock.

    The store deliberately holds no behaviour of its own; the manager owns the
    cross-cutting logic.  Exposing the shared lock lets callers reason about
    concurrency and lets the test-suite assert that one lock guards everything.
    """

    def __init__(self, lock):
        self._lock = lock
        self.items = {}


_UNSET = object()


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Facade coordinating collaborative task management.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the current ``datetime``.
        Injecting a clock keeps the system fully deterministic under test.
    """

    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._ids = itertools.count(1)
        self._notification_ids = itertools.count(1)

        # Sub-stores -- every one shares the single lock above.
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # Secondary indexes (all guarded by self._lock).
        self._username_index = {}
        self._email_index = {}
        self._tasks_by_assignee = {}
        self._messages_by_project = {}
        self._messages_by_task = {}
        self._ratings_by_ratee = {}
        self._notifications = {}

    # -- helpers ----------------------------------------------------------
    def _next_id(self):
        return next(self._ids)

    @staticmethod
    def _public(obj):
        """Return a deep copy so callers cannot mutate internal state."""
        return copy.deepcopy(obj)

    @staticmethod
    def _public_list(objs):
        return [copy.deepcopy(obj) for obj in objs]

    def _require_user(self, user_id):
        user = self.users.items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects.items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks.items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages.items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    @staticmethod
    def _clean_username(username):
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username must be a non-empty string")
        return username.strip()

    @staticmethod
    def _clean_email(email):
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("email must be non-empty and contain '@'")
        return cleaned

    def _notify(self, user_id, event, detail):
        """Record a notification for ``user_id`` (best effort, never raises)."""
        if user_id is None or user_id not in self.users.items:
            return
        note = Notification(
            id=next(self._notification_ids),
            user_id=user_id,
            event=event,
            detail=detail,
            created_at=self._now(),
        )
        self._notifications.setdefault(user_id, []).append(note)

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            uname = self._clean_username(username)
            mail = self._clean_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if uname in self._username_index:
                raise DuplicateError("username already exists")
            if mail in self._email_index:
                raise DuplicateError("email already exists")

            user = User(
                id=self._next_id(),
                username=uname,
                email=mail,
                role=role,
                created_at=self._now(),
            )
            self.users.items[user.id] = user
            self._username_index[uname] = user.id
            self._email_index[mail] = user.id
            return self._public(user)

    def get_user(self, user_id):
        with self._lock:
            return self._public(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            return self._public_list(
                self.users.items[i] for i in sorted(self.users.items)
            )

    def update_user(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET):
        with self._lock:
            user = self._require_user(user_id)

            new_username = None
            if username is not _UNSET:
                new_username = self._clean_username(username)
                owner = self._username_index.get(new_username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already exists")

            new_email = None
            if email is not _UNSET:
                new_email = self._clean_email(email)
                owner = self._email_index.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already exists")

            if role is not _UNSET and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_username is not None:
                self._username_index.pop(user.username, None)
                user.username = new_username
                self._username_index[new_username] = user_id
            if new_email is not None:
                self._email_index.pop(user.email, None)
                user.email = new_email
                self._email_index[new_email] = user_id
            if role is not _UNSET:
                user.role = role
            return self._public(user)

    def delete_user(self, user_id):
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            for task_id in self._tasks_by_assignee.get(user_id, set()):
                task = self.tasks.items.get(task_id)
                if task is not None and task.status is not TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks assigned")

            self.users.items.pop(user_id, None)
            self._username_index.pop(user.username, None)
            self._email_index.pop(user.email, None)
            self._tasks_by_assignee.pop(user_id, None)
            self._ratings_by_ratee.pop(user_id, None)
            self._notifications.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be a non-empty string")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._next_id(),
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._now(),
            )
            self.projects.items[project.id] = project
            return self._public(project)

    def get_project(self, project_id):
        with self._lock:
            return self._public(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            return self._public_list(
                self.projects.items[i] for i in sorted(self.projects.items)
            )

    def update_project(
        self,
        project_id,
        name=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
        description=_UNSET,
    ):
        with self._lock:
            project = self._require_project(project_id)

            if name is not _UNSET:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name must be non-empty")

            new_start = project.start_date if start_date is _UNSET else start_date
            new_end = project.end_date if end_date is _UNSET else end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not _UNSET:
                project.name = name.strip()
            if start_date is not _UNSET:
                project.start_date = start_date
            if end_date is not _UNSET:
                project.end_date = end_date
            if description is not _UNSET:
                project.description = description or ""
            return self._public(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            doomed_tasks = [
                tid
                for tid, task in self.tasks.items.items()
                if task.project_id == project_id
            ]
            for tid in doomed_tasks:
                task = self.tasks.items.pop(tid)
                self._detach_assignee(task.assignee_id, tid)
                self._purge_task_messages(tid)

            doomed_messages = [
                mid
                for mid, msg in self.messages.items.items()
                if msg.project_id == project_id
            ]
            for mid in doomed_messages:
                self._purge_message(mid)

            self.projects.items.pop(project_id, None)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(
        self,
        project_id,
        title,
        assignee_id=None,
        deadline=None,
        description="",
        priority=Priority.MEDIUM,
    ):
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must be a non-empty string")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            if priority is None:
                priority = Priority.MEDIUM
            if not isinstance(priority, Priority):
                raise ValidationError("priority must be a Priority")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title.strip(),
                description=description or "",
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                priority=priority,
                created_at=self._now(),
            )
            self.tasks.items[task.id] = task
            if assignee_id is not None:
                self._attach_assignee(assignee_id, task.id)
                self._notify(
                    assignee_id, "task_assigned",
                    "Assigned to task '{0}'".format(task.title),
                )
            return self._public(task)

    def get_task(self, task_id):
        with self._lock:
            return self._public(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = [
                t for t in self.tasks.items.values() if t.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return self._public_list(tasks)

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._require_user(assignee_id)
            ids = sorted(self._tasks_by_assignee.get(assignee_id, set()))
            return self._public_list(self.tasks.items[i] for i in ids)

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            if task.assignee_id != assignee_id:
                self._detach_assignee(task.assignee_id, task_id)
                task.assignee_id = assignee_id
                self._attach_assignee(assignee_id, task_id)
                self._notify(
                    assignee_id, "task_assigned",
                    "Assigned to task '{0}'".format(task.title),
                )
            return self._public(task)

    def reassign_task(self, task_id, new_assignee_id):
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            self._detach_assignee(task.assignee_id, task_id)
            task.assignee_id = None
            return self._public(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return self._public(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status is TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status is TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status is TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            if task.assignee_id is not None:
                self._notify(
                    task.assignee_id, "status_changed",
                    "Task '{0}' is now {1}".format(task.title, status.value),
                )
            return self._public(task)

    # -- assignee index helpers ------------------------------------------
    def _attach_assignee(self, assignee_id, task_id):
        if assignee_id is None:
            return
        self._tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)

    def _detach_assignee(self, assignee_id, task_id):
        if assignee_id is None:
            return
        bucket = self._tasks_by_assignee.get(assignee_id)
        if bucket is not None:
            bucket.discard(task_id)
            if not bucket:
                self._tasks_by_assignee.pop(assignee_id, None)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ):
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            built = self._build_attachments(attachments, author_id)
            text = body if isinstance(body, str) else ""
            if not text.strip() and not built:
                raise ValidationError("message requires a body or an attachment")

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=self._now(),
            )
            self.messages.items[message.id] = message
            if project_id is not None:
                self._messages_by_project.setdefault(project_id, set()).add(message.id)
            if task_id is not None:
                self._messages_by_task.setdefault(task_id, set()).add(message.id)
                target = self.tasks.items.get(task_id)
                if target is not None and target.assignee_id not in (None, author_id):
                    self._notify(
                        target.assignee_id, "comment_added",
                        "New comment on task '{0}'".format(target.title),
                    )
            return self._public(message)

    def _build_attachments(self, attachments, uploader_id):
        built = []
        if not attachments:
            return built
        now = self._now()
        for entry in attachments:
            filename, data = entry
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must be non-empty")
            built.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=now,
                    id=self._next_id(),
                )
            )
        return built

    def _can_modify_message(self, message, actor_id):
        if actor_id == message.author_id:
            return True
        actor = self.users.items.get(actor_id)
        return actor is not None and actor.role is UserRole.ADMIN

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if not self._can_modify_message(message, editor_id):
                raise AuthorizationError("only the author may edit this message")
            text = new_body if isinstance(new_body, str) else ""
            if not text.strip() and not message.attachments:
                raise ValidationError("message body cannot be empty")
            message.body = text
            message.edited_at = self._now()
            return self._public(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if not self._can_modify_message(message, uploader_id):
                raise AuthorizationError("only the author may attach files")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must be non-empty")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._now(),
                    id=self._next_id(),
                )
            )
            return self._public(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self._messages_by_project.get(project_id, set()))
            return self._public_list(self.messages.items[i] for i in ids)

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self._messages_by_task.get(task_id, set()))
            return self._public_list(self.messages.items[i] for i in ids)

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if not self._can_modify_message(message, requester_id):
                raise AuthorizationError("only the author may delete this message")
            self._purge_message(message_id)

    def _purge_message(self, message_id):
        message = self.messages.items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self._messages_by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message_id)
                if not bucket:
                    self._messages_by_project.pop(message.project_id, None)
        if message.task_id is not None:
            bucket = self._messages_by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message_id)
                if not bucket:
                    self._messages_by_task.pop(message.task_id, None)

    def _purge_task_messages(self, task_id):
        ids = list(self._messages_by_task.get(task_id, set()))
        for mid in ids:
            self._purge_message(mid)

    # ------------------------------------------------------------------
    # Notifications
    # ------------------------------------------------------------------
    def get_notifications(self, user_id, unread_only=False):
        with self._lock:
            self._require_user(user_id)
            notes = self._notifications.get(user_id, [])
            if unread_only:
                notes = [n for n in notes if not n.read]
            return self._public_list(sorted(notes, key=lambda n: n.id))

    def mark_notification_read(self, user_id, notification_id):
        with self._lock:
            self._require_user(user_id)
            for note in self._notifications.get(user_id, []):
                if note.id == notification_id:
                    note.read = True
                    return self._public(note)
            raise NotFoundError("notification {0} not found".format(notification_id))

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _assignee_tasks(self, user_id):
        ids = self._tasks_by_assignee.get(user_id, set())
        return [self.tasks.items[i] for i in ids if i in self.tasks.items]

    @staticmethod
    def _completion_rate(tasks):
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status is TaskStatus.COMPLETED)
        return completed / len(tasks)

    @staticmethod
    def _average_completion_time(tasks):
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status is TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._completion_rate(self._assignee_tasks(user_id))

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(self._assignee_tasks(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1-5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self._ratings_by_ratee.setdefault(ratee_id, []).append(rating)
            self._notify(
                ratee_id, "rating_received",
                "You received a {0}-star rating".format(score),
            )
            return self._public(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_by_ratee.get(user_id, [])
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": self._public_list(
                    sorted(ratings, key=lambda r: r.id)
                ),
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            ratings = self._ratings_by_ratee.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": sum(
                    1 for t in tasks if t.status is TaskStatus.COMPLETED
                ),
                "in_progress_tasks": sum(
                    1 for t in tasks if t.status is TaskStatus.IN_PROGRESS
                ),
                "not_started_tasks": sum(
                    1 for t in tasks if t.status is TaskStatus.NOT_STARTED
                ),
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def _user_stats(self, user, tasks):
        return {
            "user_id": user.id,
            "username": user.username,
            "total_tasks": len(tasks),
            "completed_tasks": sum(
                1 for t in tasks if t.status is TaskStatus.COMPLETED
            ),
            "in_progress_tasks": sum(
                1 for t in tasks if t.status is TaskStatus.IN_PROGRESS
            ),
            "not_started_tasks": sum(
                1 for t in tasks if t.status is TaskStatus.NOT_STARTED
            ),
            "completion_rate": self._completion_rate(tasks),
            "average_completion_time": self._average_completion_time(tasks),
        }

    def project_progress_report(self, project_id):
        with self._lock:
            project = self._require_project(project_id)
            now = self._now()
            tasks = [
                t for t in self.tasks.items.values() if t.project_id == project_id
            ]

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.status is not TaskStatus.COMPLETED
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    per_assignee.setdefault(task.assignee_id, []).append(task)

            per_assignee_summary = {}
            for assignee_id, assigned in per_assignee.items():
                per_assignee_summary[assignee_id] = {
                    "total_tasks": len(assigned),
                    "completed_tasks": sum(
                        1 for t in assigned if t.status is TaskStatus.COMPLETED
                    ),
                    "completion_rate": self._completion_rate(assigned),
                }

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "generated_at": now,
                "total_tasks": len(tasks),
                "status_counts": status_counts,
                "completed_tasks": status_counts[TaskStatus.COMPLETED.value],
                "pending_tasks": status_counts[TaskStatus.NOT_STARTED.value]
                + status_counts[TaskStatus.IN_PROGRESS.value],
                "overdue_tasks": overdue,
                "completion_rate": self._completion_rate(tasks),
                "per_assignee": per_assignee_summary,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            now = self._now()
            if project_id is not None:
                self._require_project(project_id)
                scope = [
                    t
                    for t in self.tasks.items.values()
                    if t.project_id == project_id
                ]
            else:
                scope = list(self.tasks.items.values())

            by_user = {}
            for task in scope:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                user = self.users.items.get(user_id)
                if user is None:
                    continue
                stats = self._user_stats(user, by_user[user_id])
                ratings = self._ratings_by_ratee.get(user_id, [])
                stats["rating_count"] = len(ratings)
                stats["rating_average"] = (
                    sum(r.score for r in ratings) / len(ratings)
                    if ratings
                    else 0.0
                )
                rows.append(stats)

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "generated_at": now,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            user = self._require_user(user_id)
            tasks = sorted(self._assignee_tasks(user_id), key=lambda t: t.id)
            ratings = self._ratings_by_ratee.get(user_id, [])
