    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if report_format is ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    @staticmethod
    def _scalar(value):
        if isinstance(value, datetime):
            return value.isoformat()
        if isinstance(value, enum.Enum):
            return value.value
        return value

    def _report_to_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list):
            keys = []
            for row in rows:
                if isinstance(row, dict):
                    for key in row:
                        if key not in keys:
                            keys.append(key)
            if not keys:
                keys = ["user_id"]
            writer.writerow(keys)
            for row in rows:
                if isinstance(row, dict):
                    writer.writerow([self._scalar(row.get(k, "")) for k in keys])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                if isinstance(value, dict):
                    for sub_key, sub_value in value.items():
                        writer.writerow(
                            [
                                "{0}.{1}".format(key, sub_key),
                                self._scalar(sub_value),
                            ]
                        )
                elif isinstance(value, list):
                    writer.writerow([key, "{0} items".format(len(value))])
                else:
                    writer.writerow([key, self._scalar(value)])
        return output.getvalue()

    def _report_to_lines(self, report):
        lines = ["Office Task Collaboration Manager Report"]
        lines.append("Type: {0}".format(report.get("report_type", "report")))
        for key, value in report.items():
            if key == "report_type":
                continue
            if key == "rows" and isinstance(value, list):
                lines.append("rows:")
                for row in value:
                    if isinstance(row, dict):
                        lines.append(
                            "  "
                            + ", ".join(
                                "{0}={1}".format(k, self._scalar(v))
                                for k, v in row.items()
                            )
                        )
            elif isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append(
                        "  {0}: {1}".format(sub_key, self._scalar(sub_value))
                    )
            elif isinstance(value, list):
                lines.append("{0}: {1} items".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, self._scalar(value)))
        return lines

    def _report_to_pdf(self, report):
        return self._build_pdf(self._report_to_lines(report))

    @staticmethod
    def _build_pdf(text_lines):
        def escape(text):
            return (
                text.replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )

        if not text_lines:
            text_lines = [""]

        content = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
        for index, line in enumerate(text_lines):
            safe = escape(str(line))
            if index == 0:
                content.append("({0}) Tj".format(safe))
            else:
                content.append("T* ({0}) Tj".format(safe))
        content.append("ET")
        stream = "\n".join(content).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
            ),
            b"<< /Length "
            + str(len(stream)).encode("ascii")
            + b" >>\nstream\n"
            + stream
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n".format(number).encode("ascii")
            pdf += body
            pdf += b"\nendobj\n"

        xref_position = len(pdf)
        size = len(objects) + 1
        pdf += "xref\n0 {0}\n".format(size).encode("ascii")
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += "<< /Size {0} /Root 1 0 R >>\n".format(size).encode("ascii")
        pdf += b"startxref\n"
        pdf += "{0}\n".format(xref_position).encode("ascii")
        pdf += b"%%EOF"
        return bytes(pdf)


